import React from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import DarkModeToggle from "./components/DarkModeToggle";
import { FaGithub, FaLinkedin } from "react-icons/fa";

function App() {
  const { scrollY } = useScroll();
  const backgroundY = useTransform(scrollY, [0, 500], [0, -200]); // Moves up as you scroll

  return (
    <div className="relative min-h-screen">
      {/* Background Image with Parallax Effect */}
      <motion.div
        className="fixed top-0 left-0 w-full h-full bg-cover bg-center z-[-1]"
        style={{
          backgroundImage: "url('/background.jpg')",
          backgroundSize: "cover",
          backgroundAttachment: "fixed",
          y: backgroundY,
        }}
      ></motion.div>

      {/* Navbar */}
      <nav className="p-6 flex justify-between items-center shadow-md bg-gray-100 dark:bg-gray-800 fixed top-0 w-full z-50">
        <h1 className="text-2xl font-bold">Ritesh Chakramani</h1>
        <div className="space-x-6 flex items-center">
          <a href="#about" className="hover:text-blue-500 transition">About</a>
          <a href="#skills" className="hover:text-blue-500 transition">Skills</a>
          <a href="#projects" className="hover:text-blue-500 transition">Projects</a>
          <a href="#contact" className="hover:text-blue-500 transition">Contact</a>
          <a href="https://github.com/your-github" target="_blank" rel="noopener noreferrer">
            <FaGithub className="text-2xl hover:text-gray-600 transition" />
          </a>
          <a href="https://linkedin.com/in/your-linkedin" target="_blank" rel="noopener noreferrer">
            <FaLinkedin className="text-2xl hover:text-blue-700 transition" />
          </a>
          <DarkModeToggle />
        </div>
      </nav>

      {/* Hero Section */}
      <main className="p-20 flex flex-col items-center text-center mt-16 text-white">
        <motion.h2
          className="text-5xl font-bold"
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1 }}
        >
          Hi, I'm Ritesh Chakramani 👋
        </motion.h2>
        <motion.p
          className="mt-4 text-lg max-w-xl"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.5, duration: 1 }}
        >
          A passionate **Full-Stack Developer** skilled in **React.js & Python**. I build web applications with seamless UI & performance.
        </motion.p>
      </main>

      {/* Other Sections */}
      <section id="about" className="p-10 text-center max-w-3xl mx-auto text-white">
        <h3 className="text-3xl font-semibold mb-4">About Me</h3>
        <p className="text-lg">
          I love building web applications that solve real-world problems. With expertise in **React.js, Python, Flask, and Machine Learning**, I create modern, scalable, and efficient solutions.
        </p>
      </section>

      {/* Footer */}
      <footer className="p-4 text-center border-t border-gray-300 dark:border-gray-700 text-white">
        © 2025 Ritesh Chakramani. All rights reserved.
      </footer>
    </div>
  );
}

export default App;
